-- Python code execution mode - run Python code with live evaluation
local function handlePythonCode(code, searchId, callback)
    if code == "" then
        callback(searchId, {})
        return
    end

    -- Execute Python code and get result
    local output, status = hs.execute(string.format('~/repos/github/g0t4/dotfiles/.venv/bin/python -c "%s"', code:gsub('"', '\\"')))

    if status then
        -- Success - show output
        local result = output and output:gsub("%s+$", "") or ""  -- Trim trailing whitespace
        if result == "" then
            callback(searchId, {{
                text = "No output",
                subText = code,
                pythonCode = code,
                pythonResult = "",
                image = hs.image.imageFromName("NSActionTemplate"),
            }})
        else
            callback(searchId, {{
                text = result,
                subText = code,
                pythonCode = code,
                pythonResult = result,
                image = hs.image.imageFromName("NSActionTemplate"),
            }})
        end
    else
        -- Error - show error message
        local errorMsg = output and output:gsub("%s+$", "") or "Unknown error"
        callback(searchId, {{
            text = "Error: " .. errorMsg,
            subText = code,
            pythonCode = code,
            pythonResult = nil,
            image = hs.image.imageFromName("NSCaution"),
        }})
    end
    return function() end  -- No-op cancel
end

